class SecureStorageService {
  static async store(key, value) {
    if (!key || value === undefined || value === null) {
      throw new PaymentError('STORAGE_ERROR', 'Invalid key or value for secure storage');
    }
    try {
      const serialized = typeof value === 'string' ? value : JSON.stringify(value);
      await Keychain.setGenericPassword(key, serialized, {
        service: `payment_module_${key}`,
        accessControl: Keychain.ACCESS_CONTROL.BIOMETRY_ANY_OR_DEVICE_PASSCODE,
        accessible: Keychain.ACCESSIBLE.WHEN_UNLOCKED_THIS_DEVICE_ONLY,
      });
    } catch (error) {
      throw new PaymentError('STORAGE_ERROR', 'Failed to store secure data', error);
    }
  }

  static async retrieve(key) {
    if (!key) {
      throw new PaymentError('STORAGE_ERROR', 'Invalid key for secure storage retrieval');
    }
    try {
      const credentials = await Keychain.getGenericPassword({
        service: `payment_module_${key}`,
      });
      if (credentials) {
        try {
          return JSON.parse(credentials.password);
        } catch {
          return credentials.password;
        }
      }
      return null;
    } catch (error) {
      throw new PaymentError('STORAGE_ERROR', 'Failed to retrieve secure data', error);
    }
  }

  static async remove(key) {
    if (!key) {
      throw new PaymentError('STORAGE_ERROR', 'Invalid key for secure storage removal');
    }
    try {
      await Keychain.resetGenericPassword({
        service: `payment_module_${key}`,
      });
    } catch (error) {
      throw new PaymentError('STORAGE_ERROR', 'Failed to remove secure data', error);
    }
  }

  static async clearAll() {
    const keys = [
      'payment_token',
      'wallet_credentials',
      'session_data',
      'cached_payment_methods',
    ];
    for (const key of keys) {
      try {
        await SecureStorageService.remove(key);
      } catch {
        // Continue clearing other keys
      }
    }
  }
}

