// INPUT VALIDATION
// ============================================================

class PaymentValidator {
  static CARD_PATTERNS = {
    visa: /^4[0-9]{12}(?:[0-9]{3})?$/,
    mastercard: /^5[1-5][0-9]{14}$/,
    amex: /^3[47][0-9]{13}$/,
    discover: /^6(?:011|5[0-9]{2})[0-9]{12}$/,
  };

  static sanitizeString(input) {
    if (typeof input !== 'string') return '';
    return input.replace(/[<>\"'&\\]/g, '').trim();
  }

  static validateAmount(amount, currency) {
    if (typeof amount !== 'number' || !Number.isFinite(amount)) {
      throw new PaymentError('VALIDATION_ERROR', 'Amount must be a finite number');
    }
    if (amount <= 0) {
      throw new PaymentError('VALIDATION_ERROR', 'Amount must be positive');
    }
    if (amount > 999999.99) {
      throw new PaymentError('VALIDATION_ERROR', 'Amount exceeds maximum allowed');
    }

    const decimalPlaces = (amount.toString().split('.')[1] || '').length;
    const zeroDecimalCurrencies = ['JPY', 'KRW', 'VND'];
    const maxDecimals = zeroDecimalCurrencies.includes(currency?.toUpperCase()) ? 0 : 2;

    if (decimalPlaces > maxDecimals) {
      throw new PaymentError('VALIDATION_ERROR', `Amount cannot have more than ${maxDecimals} decimal places for ${currency}`);
    }

    return Math.round(amount * Math.pow(10, maxDecimals));
  }

  static validateCurrency(currency) {
    const validCurrencies = ['USD', 'EUR', 'GBP', 'JPY', 'CAD', 'AUD', 'CHF', 'KRW', 'VND', 'INR', 'BRL', 'MXN'];
    const sanitized = this.sanitizeString(currency).toUpperCase();
    if (!validCurrencies.includes(sanitized)) {
      throw new PaymentError('VALIDATION_ERROR', `Unsupported currency: ${sanitized}`);
    }
    return sanitized;
  }

  static validateCardNumber(cardNumber) {
    const cleaned = cardNumber.replace(/[\s-]/g, '');
    if (!/^\d{13,19}$/.test(cleaned)) {
      throw new PaymentError('VALIDATION_ERROR', 'Invalid card number format');
    }
    if (!this.luhnCheck(cleaned)) {
      throw new PaymentError('VALIDATION_ERROR', 'Invalid card number');
    }
    return cleaned;
  }

  static luhnCheck(cardNumber) {
    let sum = 0;
    let isEven = false;
    for (let i = cardNumber.length - 1; i >= 0; i--) {
      let digit = parseInt(cardNumber[i], 10);
      if (isEven) {
        digit *= 2;
        if (digit > 9) digit -= 9;
      }
      sum += digit;
      isEven = !isEven;
    }
    return sum % 10 === 0;
  }

  static validateExpiry(month, year) {
    const m = parseInt(month, 10);
    const y = parseInt(year, 10);
    if (isNaN(m) || isNaN(y) || m < 1 || m > 12) {
      throw new PaymentError('VALIDATION_ERROR', 'Invalid expiry date');
    }
    const fullYear = y < 100 ? 2000 + y : y;
    const expiry = new Date(fullYear, m, 0, 23, 59, 59);
    if (expiry < new Date()) {
      throw new PaymentError('VALIDATION_ERROR', 'Card has expired');
    }
    return { month: m, year: fullYear };
  }

  static validateCVV(cvv, cardType = 'visa') {
    const cleaned = cvv.replace(/\D/g, '');
    const expectedLength = cardType === 'amex' ? 4 : 3;
    if (cleaned.length !== expectedLength) {
      throw new PaymentError('VALIDATION_ERROR', 'Invalid CVV');
    }
    return cleaned;
  }

  static validateEmail(email) {
    const sanitized = this.sanitizeString(email).toLowerCase();
    const emailRegex = /^[a-z0-9._%+\-]+@[a-z0-9.\-]+\.[a-z]{2,}$/;
    if (!emailRegex.test(sanitized)) {
      throw new PaymentError('VALIDATION_ERROR', 'Invalid email address');
    }
    return sanitized;
  }

  static detectCardType(cardNumber) {
    const cleaned = cardNumber.replace(/[\s-]/g, '');
    for (const [type, pattern] of Object.entries(this.CARD_PATTERNS)) {
      if (pattern.test(cleaned)) return type;
    }
    return 'unknown';
  }

  static validatePaymentRequest(request) {
    if (!request || typeof request !== 'object') {
      throw new PaymentError('VALIDATION_ERROR', 'Invalid payment request');
    }

    const required = ['amount', 'currency', 'paymentMethod'];
    for (const field of required) {
      if (request[field] === undefined || request[field] === null) {
        throw new PaymentError('VALIDATION_ERROR', `Missing required field: ${field}`);
      }
    }

    return {
      amount: this.validateAmount(request.amount, request.currency),
      currency: this.validateCurrency(request.currency),
      paymentMethod: request.paymentMethod,
      description: request.description ? this.sanitizeString(request.description).substring(0, 255) : '',
      metadata: request.metadata || {},
    };
  }
}

// ============================================================
// ENCRYPTION SERVICE
// ============================================================

class EncryptionService {
  static generateNonce() {
    return uuidv4().replace(/-/g, '') + Date.now().toString(36);
  }

  static hashData(data) {
    return CryptoJS.SHA256(JSON.stringify(data)).toString();
  }

  static encryptPayload(data, publicKey) {
    if (!data || !publicKey) {
      throw new PaymentError('ENCRYPTION_ERROR', 'Missing data or key for encryption');
    }
    try {
      const nonce = this.generateNonce();
      const payload = JSON.stringify({
        data,
        nonce,
        timestamp: Date.now(),
      });
      // In production, use RSA/ECDH with the provider's public key
      // This is a symmetric placeholder - replace with asymmetric encryption
      const encrypted = CryptoJS.AES.encrypt(payload, publicKey, {
        mode: CryptoJS.mode.GCM || CryptoJS.mode.CBC,
        padding: CryptoJS.pad.Pkcs7,
      }).toString();
      return {
        encryptedData: encrypted,
        nonce,
        algorithm: 'AES-256-GCM',
      };
    } catch (error) {
      throw new PaymentError('ENCRYPTION_ERROR', 'Failed to encrypt payment data', error);
    }
  }

  static generateRequestSignature(payload, secretKey) {
    const timestamp = Date.now().toString();
    const message = `${timestamp}.${JSON.stringify(payload)}`;
    const signature = CryptoJS.HmacSHA256(message, secretKey).toString();
    return { signature, timestamp };
  }

  static maskCardNumber(cardNumber) {
    if (!cardNumber || cardNumber.length < 8) return '****';
    const cleaned = cardNumber.replace(/\D/g, '');
    return `****${cleaned.slice(-4)}`;
  }

  static maskSensitiveData(data) {
    if (!data || typeof data !== 'object') return data;
    const masked = { ...data };
    const sensitiveFields = ['cardNumber', 'cvv', 'cvc', 'securityCode', 'pin', 'password', 'token', 'secretKey'];
    for (const key of Object.keys(masked)) {
      if (sensitiveFields.includes(key)) {
        if (key === 'cardNumber') {
          masked[key] = this.maskCardNumber(masked[key]);
        } else {
          masked[key] = '***REDACTED***';
        }
      } else if (typeof masked[key] === 'object' && masked[key] !== null) {
        masked[key] = this.maskSensitiveData(masked[key]);
      }
    }
    return masked;
  }
}

