class AuditLogger {
  static logs = [];
  static MAX_LOGS = 1000;

  static log(event, data = {}, level = 'INFO') {
    const entry = {
      id: uuidv4(),
      timestamp: new Date().toISOString(),
      level,
      event,
      data: EncryptionService.maskSensitiveData(data),
      platform: Platform.OS,
    };

    this.logs.push(entry);
    if (this.logs.length > this.MAX_LOGS) {
      this.logs = this.logs.slice(-this.MAX_LOGS);
    }

    if (__DEV__) {
      console.log(`[PaymentAudit][${level}] ${event}`, entry.data);
    }

    return entry;
  }

  static error(event, error, data = {}) {
    return this.log(event, {
      ...data,
      error: error instanceof PaymentError ? error.toSafeObject() : { message: 'Internal error' },
    }, 'ERROR');
  }

  static getRecentLogs(count = 50) {
    return this.logs.slice(-count);
  }

  static async flush() {
    // In production, send logs to secure logging service
    const logsToSend = [...this.logs];
    this.logs = [];
    return logsToSend;
  }
}

// ============================================================
// RATE LIMITER
// ============================================================

class RateLimiter {
  constructor(maxRequests = 10, windowMs = 60000) {
    this.maxRequests = maxRequests;
    this.windowMs = windowMs;
    this.requests = [];
  }

  canProceed() {
    const now = Date.now();
    this.requests = this.requests.filter(t => now - t < this.windowMs);
    if (this.requests.length >= this.maxRequests) {
      return false;
    }
    this.requests.push(now);
    return true;
  }

  getRemainingRequests() {
    const now = Date.now();
    this.requests = this.requests.filter(t => now - t < this.windowMs);
    return Math.max(0, this.maxRequests - this.requests.length);
  }

  getRetryAfterMs() {
    if (this.requests.length === 0) return 0;
    const oldest = Math.min(...this.requests);
    return Math.max(0, this.windowMs - (Date.now() - oldest));
  }
}

// ============================================================
// IDEMPOTENCY MANAGER
// ============================================================

class IdempotencyManager {
  constructor() {
    this.keys = new Map();
  }

  generateKey(operation, params) {
    const hash = EncryptionService.hashData({ operation, params, timestamp: Math.floor(Date.now() / 1000) });
    return `idem_${hash}`;
  }

  async checkAndSet(key) {
    this.cleanup();
    if (this.keys.has(key)) {
      const existing = this.keys.get(key);
      if (existing.status === 'pending') {
        throw new PaymentError('DUPLICATE_REQUEST', 'A similar transaction is already being processed');
      }
      if (existing.status === 'completed' && existing.result) {
        return { isDuplicate: true, result: existing.result };
      }
    }
    this.keys.set(key, { status: 'pending', createdAt: Date.now() });
    return { isDuplicate: false };
  }

  complete(key, result) {
    if (this.keys.has(key)) {
      this.keys.set(key, { status: 'completed', result, createdAt: Date.now() });
    }
  }

  fail(key) {
    this.keys.delete(key);
  }

  cleanup() {
    const now = Date.now();
    for (const [key, value] of this.keys.entries()) {
      if (now - value.createdAt > PAYMENT_CONFIG.IDEMPOTENCY_KEY_TTL_MS) {
        this.keys.delete(key);
      }
    }
  }
}

// ============================================================
// SECURE HTTP CLIENT
// ============================================================

class SecureHttpClient {
  constructor(baseUrl, authProvider) {
    this.baseUrl = baseUrl;
    this.authProvider = authProvider;
    this.rateLimiter = new RateLimiter(30, 60000);
  }

  async request(method, path, body = null, options = {}) {
    if (!this.rateLimiter.canProceed()) {
      const retryAfter = this.rateLimiter.getRetryAfterMs();
      throw new PaymentError('RATE_LIMITED', `Too many requests. Retry after ${Math.ceil(retryAfter / 1000)}s`);
    }

    const url = `${this.baseUrl}${path}`;
    const headers = {
      'Content-Type': 'application/json',
      'Accept': 'application/json',
      'X-Request-ID': uuidv4(),
      'X-Platform': Platform.OS,
      'X-Client-Version': '1.0.0',
      ...options.headers,
    };

    if (options.idempotencyKey) {
      headers['Idempotency-Key'] = options.idempotencyKey;
    }

    const token = await this.authProvider.getToken();
    if (token) {
      headers['Authorization'] = `Bearer ${token}`;
    }

    const controller = new AbortController();
    const timeout = setTimeout(() => controller.abort(), options.timeout || PAYMENT_CONFIG.TIMEOUT_MS);

    try {
      AuditLogger.log('HTTP_REQUEST', { method, path, requestId: headers['X-Request-ID'] });

      const fetchOptions = {
        method,
        headers,
        signal: controller.signal,
      };

      if (body && ['POST', 'PUT', 'PATCH'].includes(method)) {
        fetchOptions.body = JSON.stringify(body);
      }

      const response = await fetch(url, fetchOptions);
      clearTimeout(timeout);

      const responseData = await response.json().catch(() => null);

      if (!response.ok) {
        const errorMessage = responseData?.message || `HTTP ${response.status}`;
        const errorCode = responseData?.code || `HTTP_${response.status}`;
        AuditLogger.error('HTTP_ERROR', new PaymentError(errorCode, errorMessage), {
          status: response.status,
          path,
        });
        throw new PaymentError(errorCode, errorMessage);
      }

      AuditLogger.log('HTTP_RESPONSE', { status: response.status, path });
      return responseData;
    } catch (error) {
      clearTimeout(timeout);
      if (error.name === 'AbortError') {
        throw new PaymentError('TIMEOUT', 'Request timed out');
      }
      if (error instanceof PaymentError) throw error;
      throw new PaymentError('NETWORK_ERROR', 'Network request failed', error);
    }
  }

  async post(path, body, options = {}) {
    return this.request('POST', path, body, options);
  }

  async get(path, options = {}) {
    return this.request('GET', path, null, options);
  }

  async delete(path, options = {}) {
    return this.request('DELETE', path, null, options);
  }
}

// ============================================================
// AUTH PROVIDER
// ============================================================

class PaymentAuthProvider {
  constructor() {
    this.tokenData = null;
  }

  async getToken() {
    if (this.tokenData && !this.isTokenExpired()) {
      return this.tokenData.accessToken;
    }

    const stored = await SecureStorageService.retrieve('payment_token');
    if (stored && !this.isTokenDataExpired(stored)) {
      this.tokenData = stored;
      return stored.accessToken;
    }

    return null;
  }

  async setToken(tokenData) {
    if (!tokenData || !tokenData.accessToken) {
      throw new PaymentError('AUTH_ERROR', 'Invalid token data');
    }
    this.tokenData = {
      ...tokenData,
      storedAt: Date.now(),
    };
    await SecureStorageService.store('payment_token', this.tokenData);
  }

  async clearToken() {
    this.tokenData = null;
    await SecureStorageService.remove('payment_token');
  }

  isTokenExpired() {
    return this.isTokenDataExpired(this.tokenData);
  }

  isTokenDataExpired(data) {
    if (!data || !data.expiresAt) return true;
    return Date.now() >= (data.expiresAt - PAYMENT_CONFIG.TOKEN_REFRESH_BUFFER_MS);
  }
}

