// IN-APP PURCHASE SERVICE (iOS & Android)
// ============================================================

class InAppPurchaseService {
  constructor() {
    this.initialized = false;
    this.purchaseListeners = [];
    this.pendingPurchases = new Map();
  }

  async initialize() {
    if (this.initialized) return;

    try {
      AuditLogger.log('IAP_INIT', { platform: Platform.OS });

      // Platform-specific initialization
      if (Platform.OS === 'ios') {
        await this.initializeIOS();
      } else if (Platform.OS === 'android') {
        await this.initializeAndroid();
      }

      this.initialized = true;
      AuditLogger.log('IAP_INIT_SUCCESS', { platform: Platform.OS });
    } catch (error) {
      AuditLogger.error('IAP_INIT_FAILED', error);
      throw new PaymentError('IAP_INIT_ERROR', 'Failed to initialize in-app purchases', error);
    }
  }

  async initializeIOS() {
    // Uses StoreKit via native module
    const { RNPaymentBridge } = NativeModules;
    if (!RNPaymentBridge) {
      throw new PaymentError('IAP_UNAVAILABLE', 'Payment bridge not available on iOS');
    }
    await RNPaymentBridge.initializeStoreKit();
  }

  async initializeAndroid() {
    // Uses Google Play Billing via native module
    const { RNPaymentBridge } = NativeModules;
    if (!RNPaymentBridge) {
      throw new PaymentError('IAP_UNAVAILABLE', 'Payment bridge not available on Android');
    }
    await RNPaymentBridge.initializeBillingClient();
  }

  async getProducts(productIds) {
    if (!this.initialized) await this.initialize();
    if (!Array.isArray(productIds) || productIds.length === 0) {
      throw new PaymentError('VALIDATION_ERROR', 'Product IDs must be a non-empty array');
    }

    // Sanitize product IDs
    const sanitizedIds = productIds.map(id => PaymentValidator.sanitizeString(id)).filter(Boolean);

    try {
      const { RNPaymentBridge } = NativeModules;
      const products = await RNPaymentBridge.getProducts(sanitizedIds);
      AuditLogger.log('IAP_PRODUCTS_FETCHED', { count: products.length });
      return products;
    } catch (error) {
      AuditLogger.error('IAP_PRODUCTS_FETCH_FAILED', error);
      throw new PaymentError('IAP_PRODUCTS_ERROR', 'Failed to fetch products', error);
    }
  }

  async purchaseProduct(productId, options = {}) {
    if (!this.initialized) await this.initialize();

    const sanitizedProductId = PaymentValidator.sanitizeString(productId);
    if (!sanitizedProductId) {
      throw new PaymentError('VALIDATION_ERROR', 'Invalid product ID');
    }

    const purchaseId = uuidv4();
    AuditLogger.log('IAP_PURCHASE_INITIATED', { productId: sanitizedProductId, purchaseId });

    try {
      const { RNPaymentBridge } = NativeModules;

      this.pendingPurchases.set(purchaseId, {
        productId: sanitizedProductId,
        status: 'pending',
        startedAt: Date.now(),
      });

      const result = await RNPaymentBridge.purchaseProduct(sanitizedProductId, {
        applicationUsername: options.userId ? EncryptionService.hashData(options.userId) : undefined,
        quantity: 1,
      });

      // Verify receipt server-side
      const verification = await this.verifyReceipt(result.receipt, result.transactionId);

      if (!verification.valid) {
        AuditLogger.error('IAP_RECEIPT_INVALID', new PaymentError('RECEIPT_INVALID', 'Receipt verification failed'), {
          purchaseId,
          transactionId: result.transactionId,
        });
        throw new PaymentError('RECEIPT_INVALID', 'Purchase receipt verification failed');
      }

      this.pendingPurchases.set(purchaseId, {
        ...this.pendingPurchases.get(purchaseId),
        status: 'completed',
        transactionId: result.transactionId,
      });

      AuditLogger.log('IAP_PURCHASE_COMPLETED', {
        purchaseId,
        transactionId: result.transactionId,
        productId: sanitizedProductId,
      });

      return {
        purchaseId,
        transactionId: result.transactionId,
        productId: sanitizedProductId,
        receipt: result.receipt,
        verified: true,
      };
    } catch (error) {
      this.pendingPurchases.set(purchaseId, {
        ...this.pendingPurchases.get(purchaseId),
        status: 'failed',
        error: error.code || 'UNKNOWN',
      });

      if (error instanceof PaymentError) throw error;
      AuditLogger.error('IAP_PURCHASE_FAILED', error, { purchaseId, productId: sanitizedProductId });
      throw new PaymentError('IAP_PURCHASE_ERROR', 'Purchase failed', error);
    }
  }

  async verifyReceipt(receipt, transactionId) {
    if (!receipt) {
      throw new PaymentError('VALIDATION_ERROR', 'Receipt is required for verification');
    }

    try {
      // Server-side receipt verification - NEVER verify locally only
      const authProvider = new PaymentAuthProvider();
      const httpClient = new SecureHttpClient(PAYMENT_CONFIG.API_BASE_URL, authProvider);

      const response = await httpClient.post('/api/v1/iap/verify-receipt', {
        receipt,
        transactionId,
        platform: Platform.OS,
      });

      return {
        valid: response.valid === true,
        expiresAt: response.expiresAt,
        productId: response.productId,
      };
    } catch (error) {
      AuditLogger.error('IAP_VERIFY_FAILED', error, { transactionId });
      throw new PaymentError('VERIFICATION_ERROR', 'Receipt verification failed', error);
    }
  }

  async restorePurchases() {
    if (!this.initialized) await this.initialize();

    try {
      const { RNPaymentBridge } = NativeModules;
      const restored = await RNPaymentBridge.restorePurchases();

      AuditLogger.log('IAP_RESTORE_COMPLETED', { count: restored.length });

      // Verify each restored purchase
      const verified = [];
      for (const purchase of restored) {
        try {
          const verification = await this.verifyReceipt(purchase.receipt, purchase.transactionId);
          if (verification.valid) {
            verified.push({
              ...purchase,
              verified: true,
            });
          }
        } catch {
          // Skip invalid purchases during restore
        }
      }

      return verified;
    } catch (error) {
      AuditLogger.error('IAP_RESTORE_FAILED', error);
      throw new PaymentError('IAP_RESTORE_ERROR', 'Failed to restore purchases', error);
    }
  }

  async finishTransaction(transactionId) {
    if (!transactionId) {
      throw new PaymentError('VALIDATION_ERROR', 'Transaction ID is required');
    }

    try {
      const { RNPaymentBridge } = NativeModules;
      await RNPaymentBridge.finishTransaction(transactionId);
      AuditLogger.log('IAP_TRANSACTION_FINISHED', { transactionId });
    } catch (error) {
      AuditLogger.error('IAP_FINISH_FAILED', error, { transactionId });
      throw new PaymentError('IAP_FINISH_ERROR', 'Failed to finish transaction', error);
    }
  }

  destroy() {
    this.initialized = false;
    this.pendingPurchases.clear();
    this.purchaseListeners = [];
  }
}

