class DigitalWalletService {
  constructor(httpClient) {
    this.httpClient = httpClient;
    this.idempotencyManager = new IdempotencyManager();
    this.rateLimiter = new RateLimiter(5, 60000); // 5 wallet transactions per minute
  }

  async isAvailable() {
    try {
      const { RNPaymentBridge } = NativeModules;
      if (!RNPaymentBridge) return { applePay: false, googlePay: false };

      if (Platform.OS === 'ios') {
        const canMakePayments = await RNPaymentBridge.canMakeApplePayPayments();
        return { applePay: canMakePayments, googlePay: false };
      } else if (Platform.OS === 'android') {
        const isReady = await RNPaymentBridge.isGooglePayReady();
        return { applePay: false, googlePay: isReady };
      }

      return { applePay: false, googlePay: false };
    } catch (error) {
      AuditLogger.error('WALLET_AVAILABILITY_CHECK_FAILED', error);
      return { applePay: false, googlePay: false };
    }
  }

  async processPayment(paymentRequest) {
    if (!this.rateLimiter.canProceed()) {
      throw new PaymentError('RATE_LIMITED', 'Too many wallet transactions. Please wait.');
    }

    // Validate the payment request
    const validated = PaymentValidator.validatePaymentRequest(paymentRequest);

    // Check idempotency
    const idempotencyKey = this.idempotencyManager.generateKey('wallet_payment', {
      amount: validated.amount,
      currency: validated.currency,
    });

    const idempotencyCheck = await this.idempotencyManager.checkAndSet(idempotencyKey);
    if (idempotencyCheck.isDuplicate) {
      AuditLogger.log('WALLET_DUPLICATE_PREVENTED', { idempotencyKey });
      return idempotencyCheck.result;
    }

    try {
      AuditLogger.log('WALLET_PAYMENT_INITIATED', {
        amount: validated.amount,
        currency: validated.currency,
        method: paymentRequest.walletType,
      });

      let walletToken;

      if (Platform.OS === 'ios' && paymentRequest.walletType === 'apple_pay') {
        walletToken = await this.requestApplePayToken(validated);
      } else if (Platform.OS === 'android' && paymentRequest.walletType === 'google_pay') {
        walletToken = await this.requestGooglePayToken(validated);
      } else {
        throw new PaymentError('WALLET_UNAVAILABLE', `${paymentRequest.walletType} is not available on ${Platform.OS}`);
      }

      // Process the tokenized payment server-side
      const result = await this.httpClient.post('/api/v1/wallet/charge', {
        walletToken: walletToken.token,
        walletType: paymentRequest.walletType,
        amount: validated.amount,
        currency: validated.currency,
        description: validated.description,
        metadata: validated.metadata,
      }, {
        idempotencyKey,
      });

      const paymentResult = {
        transactionId: result.transactionId,
        status: result.status,
        amount: validated.amount,
        currency: validated.currency,
        walletType: paymentRequest.walletType,
        processedAt: new Date().toISOString(),
      };

      this.idempotencyManager.complete(idempotencyKey, paymentResult);

      AuditLogger.log('WALLET_PAYMENT_COMPLETED', {
        transactionId: result.transactionId,
        amount: validated.amount,
        currency: validated.currency,
      });

      return paymentResult;
    } catch (error) {
      this.idempotencyManager.fail(idempotencyKey);
      if (error instanceof PaymentError) throw error;
      AuditLogger.error('WALLET_PAYMENT_FAILED', error);
      throw new PaymentError('WALLET_PAYMENT_ERROR', 'Wallet payment failed', error);
    }
  }

  async requestApplePayToken(paymentDetails) {
    const { RNPaymentBridge } = NativeModules;
    if (!RNPaymentBridge) {
      throw new PaymentError('WALLET_UNAVAILABLE', 'Apple Pay bridge not available');
    }

    try {
      const token = await RNPaymentBridge.requestApplePayPayment({
        merchantIdentifier: '__APPLE_PAY_MERCHANT_ID__',
        supportedNetworks: ['visa', 'mastercard', 'amex', 'discover'],
        countryCode: 'US',
        currencyCode: paymentDetails.currency,
        total: {
          label: paymentDetails.description || 'Payment',
          amount: (paymentDetails.amount / 100).toFixed(2),
        },
      });

      return { token: token.paymentData, method: 'apple_pay' };
    } catch (error) {
      if (error.code === 'USER_CANCELLED') {
        throw new PaymentError('USER_CANCELLED', 'Apple Pay payment was cancelled');
      }
      throw new PaymentError('APPLE_PAY_ERROR', 'Apple Pay request failed', error);
    }
  }

  async requestGooglePayToken(paymentDetails) {
    const { RNPaymentBridge } = NativeModules;
    if (!RNPaymentBridge) {
      throw new PaymentError('WALLET_UNAVAILABLE', 'Google Pay bridge not available');
    }

    try {
      const token = await RNPaymentBridge.requestGooglePayPayment({
        merchantName: '__GOOGLE_PAY_MERCHANT_NAME__',
        gatewayMerchantId: '__GATEWAY_MERCHANT_ID__',
        allowedCardNetworks: ['VISA', 'MASTERCARD', 'AMEX', 'DISCOVER'],
        allowedCardAuthMethods: ['PAN_ONLY', 'CRYPTOGRAM_3DS'],
        currencyCode: paymentDetails.currency,
        totalPrice: (paymentDetails.amount / 100).toFixed(2),
        totalPriceStatus: 'FINAL',
        environment: __DEV__ ? 'TEST' : 'PRODUCTION',
      });

      return { token: token.paymentData, method: 'google_pay' };
    } catch (error) {
      if (error.code === 'USER_CANCELLED') {
        throw new PaymentError('USER_CANCELLED', 'Google Pay payment was cancelled');
      }
      throw new PaymentError('GOOGLE_PAY_ERROR', 'Google Pay request failed', error);
    }
  }
}

// ============================================================
// CARD PAYMENT SERVICE
// ============================================================

class CardPaymentService {
  constructor(httpClient) {
    this.httpClient = httpClient;
    this.idempotencyManager = new IdempotencyManager();
    this.rateLimiter = new RateLimiter(5, 60000);
  }

  async tokenizeCard(cardDetails) {
    if (!cardDetails) {
      throw new PaymentError('VALIDATION_ERROR', 'Card details are required');
    }

    // Validate all card fields
    const cardNumber = PaymentValidator.validateCardNumber(cardDetails.number);
    const cardType = PaymentValidator.detectCardType(cardNumber);
    const expiry = PaymentValidator.validateExpiry(cardDetails.expiryMonth, cardDetails.expiryYear);
    const cvv = PaymentValidator.validateCVV(cardDetails.cvv, cardType);

    AuditLogger.log('CARD_TOKENIZE_INITIATED', {
      cardType,
      lastFour: cardNumber.slice(-4),
    });

    try {
      // Encrypt card data before sending
      const encryptedCard = EncryptionService.encryptPayload({
        number: cardNumber,
        expiryMonth: expiry.month,
        expiryYear: expiry.year,
        cvv,
      }, '__TOKENIZATION_PUBLIC_KEY__');

      const result = await this.httpClient.post('/api/v1/cards/tokenize', {
        encryptedData: encryptedCard.encryptedData,
        nonce: encryptedCard.nonce,
        algorithm: encryptedCard.algorithm,
      });

      AuditLogger.log('CARD_TOKENIZE_SUCCESS', {
        cardType,
        lastFour: cardNumber.slice(-4),
        tokenId: result.tokenId,
      });

      // Never store raw card data - only the token
      return {
        tokenId: result.tokenId,
        cardType,
        lastFour: cardNumber.slice(-4),
        expiryMonth: expiry.month,
        expiryYear: expiry.year,
      };
    } catch (error) {
      AuditLogger.error('CARD_TOKENIZE_FAILED', error, {
        cardType,
        lastFour: cardNumber.slice(-4),
      });
      if (error instanceof PaymentError) throw error;
      throw new PaymentError('TOKENIZATION_ERROR', 'Failed to tokenize card', error);
    }
  }

  async chargeCard(tokenId, paymentRequest) {
    if (!this.rateLimiter.canProceed()) {
      throw new PaymentError('RATE_LIMITED', 'Too many payment attempts. Please wait.');
    }

    if (!tokenId) {
      throw new PaymentError('VALIDATION_ERROR', 'Card token is required');
    }

    const validated = PaymentValidator.validatePaymentRequest({
      ...paymentRequest,
      paymentMethod: 'card',
    });

    const idempotencyKey = this.idempotencyManager.generateKey('card_charge', {
      tokenId,
      amount: validated.amount,
      currency: validated.currency,
    });

    const idempotencyCheck = await this.idempotencyManager.checkAndSet(idempotencyKey);
    if (idempotencyCheck.isDuplicate) {
      AuditLogger.log('CARD_CHARGE_DUPLICATE_PREVENTED', { idempotencyKey });
      return idempotencyCheck.result;
    }

    try {
      AuditLogger.log('CARD_CHARGE_INITIATED', {
        tokenId,
        amount: validated.amount,
        currency: validated.currency,
      });

      const result = await this.httpClient.post('/api/v1/cards/charge', {
        tokenId,
        amount: validated.amount,
        currency: validated.currency,
        description: validated.description,
        metadata: validated.metadata,
      }, {
        idempotencyKey,
      });

      const chargeResult = {
        transactionId: result.transactionId,
        status: result.status,
        amount: validated.amount,
        currency: validated.currency,
        processedAt: new Date().toISOString(),
      };

      this.idempotencyManager.complete(idempotencyKey, chargeResult);

      AuditLogger.log('CARD_CHARGE_COMPLETED', {
        transactionId: result.transactionId,
        amount: validated.amount,
        currency: validated.currency,
      });

      return chargeResult;
    } catch (error) {
      this.idempotencyManager.fail(idempotencyKey);
      if (error instanceof PaymentError) throw error;
      AuditLogger.error('CARD_CHARGE_FAILED', error);
      throw new PaymentError('CHARGE_ERROR', 'Card charge failed', error);
    }
  }

  async getSavedCards() {
    try {
      const result = await this.httpClient.get('/api/v1/cards/saved');
      return (result.cards || []).map(card => ({
        tokenId: card.tokenId,
        cardType: card.cardType,
        lastFour: card.lastFour,
        expiryMonth: card.expiryMonth,
        expiryYear: card.expiryYear,
        isDefault: card.isDefault,
      }));
    } catch (error) {
      AuditLogger.error('SAVED_CARDS_FETCH_FAILED', error);
      throw new PaymentError('FETCH_ERROR', 'Failed to fetch saved cards', error);
    }
  }

  async removeCard(tokenId) {
    if (!tokenId) {
      throw new PaymentError('VALIDATION_ERROR', 'Token ID is required');
    }

    try {
      await this.httpClient.delete(`/api/v1/cards/${encodeURIComponent(tokenId)}`);
      AuditLogger.log('CARD_REMOVED', { tokenId });
      return { success: true };
    } catch (error) {
      AuditLogger.error('CARD_REMOVE_FAILED', error, { tokenId });
      throw new PaymentError('REMOVE_ERROR', 'Failed to remove card', error);
    }
  }
}

// ============================================================
// TRANSACTION HISTORY SERVICE
// ============================================================

class TransactionHistoryService {
  constructor(httpClient) {
    this.httpClient = httpClient;
  }

  async getTransactions(options = {}) {
    const params = new URLSearchParams();
    if (options.limit) params.set('limit', Math.min(Math.max(1, parseInt(options.limit)), 100).toString());
    if (options.offset) params.set('offset', Math.max(0, parseInt(options.offset)).toString());
    if (options.status) params.set('status', PaymentValidator.sanitizeString(options.status));
    if (options.startDate) params.set('startDate', new Date(options.startDate).toISOString());
    if (options.endDate) params.set('endDate', new Date(options.endDate).toISOString());

    try {
      const result = await this.httpClient.get(`/api/v1/transactions?${params.toString()}`);
      return {
        transactions: result.transactions || [],
        total: result.total || 0,
        hasMore: result.hasMore || false,
      };
    } catch (error) {
      AuditLogger.error('TRANSACTIONS_FETCH_FAILED', error);
      throw new PaymentError('FETCH_ERROR', 'Failed to fetch transactions', error);
    }
  }

  async getTransaction(transactionId) {
    if (!transactionId) {
      throw new PaymentError('VALIDATION_ERROR', 'Transaction ID is required');
    }

    try {
      return await this.httpClient.get(`/api/v1/transactions/${encodeURIComponent(transactionId)}`);
    } catch (error) {
      AuditLogger.error('TRANSACTION_FETCH_FAILED', error, { transactionId });
      throw new PaymentError('FETCH_ERROR', 'Failed to fetch transaction', error);
    }
  }

  async requestRefund(transactionId, reason) {
    if (!transactionId) {
      throw new PaymentError('VALIDATION_ERROR', 'Transaction ID is required');
    }

    const sanitizedReason = PaymentValidator.sanitizeString(reason || '').substring(0, 500);

    try {
      AuditLogger.log('REFUND_REQUESTED', { transactionId });

      const result = await this.httpClient.post(`/api/v1/transactions/${encodeURIComponent(transactionId)}/refund`, {
        reason: sanitizedReason,
      });

      AuditLogger.log('REFUND_PROCESSED', {
        transactionId,
        refundId: result.refundId,
        status: result.status,
      });

      return result;
    } catch (error) {
      AuditLogger.error('REFUND_FAILED', error, { transactionId });
      if (error instanceof PaymentError) throw error;
      throw new PaymentError('REFUND_ERROR', 'Refund request failed', error);
    }
  }
}

// ============================================================
// MAIN PAYMENT MODULE
// ============================================================

class PaymentModule {
  constructor(config = {}) {
    this.config = {
      ...PAYMENT_CONFIG,
      ...config,
    };

    this.authProvider = new PaymentAuthProvider();
    this.httpClient = new SecureHttpClient(this.config.API_BASE_URL, this.authProvider);
    this.inAppPurchase = new InAppPurchaseService();
    this.wallet = new DigitalWalletService(this.httpClient);
    this.card = new CardPaymentService(this.httpClient);
    this.transactions = new TransactionHistoryService(this.httpClient);
    this.initialized = false;
  }

  async initialize(authToken) {
    if (this.initialized) {
      AuditLogger.log('PAYMENT_MODULE_ALREADY_INITIALIZED');
      return;
    }

    try {
      AuditLogger.log('PAYMENT_MODULE_INITIALIZING', { platform: Platform.OS });

      if (authToken) {
        await this.authProvider.setToken(authToken);
      }

      // Initialize IAP
      await this.inAppPurchase.initialize();

      this.initialized = true;
      AuditLogger.log('PAYMENT_MODULE_INITIALIZED', { platform: Platform.OS });
    } catch (error) {
      AuditLogger.error('PAYMENT_MODULE_INIT_FAILED', error);
      throw new PaymentError('INIT_ERROR', 'Payment module initialization failed', error);
    }
  }

  ensureInitialized() {
    if (!this.initialized) {
      throw new PaymentError('NOT_INITIALIZED', 'Payment module must be initialized before use');
    }
  }

  // ---- In-App Purchases ----

  async getProducts(productIds) {
    this.ensureInitialized();
    return this.inAppPurchase.getProducts(productIds);
  }

  async purchaseProduct(productId, options = {}) {
    this.ensureInitialized();
    return this.inAppPurchase.purchaseProduct(productId, options);
  }

  async restorePurchases() {
    this.ensureInitialized();
    return this.inAppPurchase.restorePurchases();
  }

  // ---- Digital Wallet ----

  async checkWalletAvailability() {
    return this.wallet.isAvailable();
  }

  async payWithWallet(paymentRequest) {
    this.ensureInitialized();
    return this.wallet.processPayment(paymentRequest);
  }

  // ---- Card Payments ----

  async addCard(cardDetails) {
    this.ensureInitialized();
    return this.card.tokenizeCard(cardDetails);
  }

  async chargeCard(tokenId, paymentRequest) {
    this.ensureInitialized();
    return this.card.chargeCard(tokenId, paymentRequest);
  }

  async getSavedCards() {
    this.ensureInitialized();
    return this.card.getSavedCards();
  }

  async removeCard(tokenId) {
    this.ensureInitialized();
    return this.card.removeCard(tokenId);
  }

  // ---- Transactions ----

  async getTransactionHistory(options = {}) {
    this.ensureInitialized();
    return this.transactions.getTransactions(options);
  }

  async getTransactionDetails(transactionId) {
    this.ensureInitialized();
    return this.transactions.getTransaction(transactionId);
  }

  async requestRefund(transactionId, reason) {
    this.ensureInitialized();
    return this.transactions.requestRefund(transactionId, reason);
  }

  // ---- Utility ----

  async updateAuthToken(tokenData) {
    await this.authProvider.setToken(tokenData);
    AuditLogger.log('AUTH_TOKEN_UPDATED');
  }

  async logout() {
    try {
      await this.authProvider.clearToken();
      await SecureStorageService.clearAll();
      this.inAppPurchase.destroy();
      this.initialized = false;
      AuditLogger.log('PAYMENT_MODULE_LOGOUT');
    } catch (error) {
      AuditLogger.error('LOGOUT_ERROR', error);
      // Force cleanup even on error
      this.initialized = false;
    }
  }

  getAuditLogs(count = 50) {
    return AuditLogger.getRecentLogs(count);
  }

  async destroy() {
    try {
      this.inAppPurchase.destroy();
      this.initialized = false;
      AuditLogger.log('PAYMENT_MODULE_DESTROYED');
    } catch (error) {
      AuditLogger.error('DESTROY_ERROR', error);
    }
  }
}

// ============================================================
// SINGLETON INSTANCE
// ============================================================

let paymentModuleInstance = null;

export function getPaymentModule(config = {}) {
  if (!paymentModuleInstance) {
    paymentModuleInstance = new PaymentModule(config);
  }
  return paymentModuleInstance;
}

export function resetPaymentModule() {
  if (paymentModuleInstance) {
    paymentModuleInstance.destroy();
    paymentModuleInstance = null;
  }
}

// ============================================================
// EXPORTS
// ============================================================

export {
  PaymentModule,
  PaymentError,
  PaymentValidator,
  EncryptionService,
  SecureStorageService,
  AuditLogger,
  InAppPurchaseService,
  DigitalWalletService,
  CardPaymentService,
  TransactionHistoryService,
};

export default PaymentModule;